import java.sql.*;

public class SecureSQLInjectionExample {
    public static void main(String[] args) {
        try {
            // User input (simulated from user)
            String userInput = "'; DROP TABLE users; --";

            // Establishing a connection to the database
            Connection connection = DriverManager.getConnection("jdbc:sqlite:/path/to/database.db");

            // Using a prepared statement with parameter binding to prevent SQL injection
            String sqlQuery = "SELECT * FROM users WHERE username=?";
            PreparedStatement preparedStatement = connection.prepareStatement(sqlQuery);
            preparedStatement.setString(1, userInput);

            // Executing the secure query
            ResultSet resultSet = preparedStatement.executeQuery();

            // Displaying results
            while (resultSet.next()) {
                System.out.println("Username: " + resultSet.getString("username"));
                System.out.println("Email: " + resultSet.getString("email"));
                System.out.println("-----------------------");
            }

        } catch (SQLException e) {
            e.printStackTrace();
        }
    }
}

